import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.oxq6d-og.js";const c=JSON.parse('{"title":"NHook ve MinHook","description":"","frontmatter":{},"headers":[],"relativePath":"hooking/strategies.md","filePath":"hooking/strategies.md"}'),i={name:"hooking/strategies.md"};function d(n,e,l,s,k,m){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="nhook-ve-minhook" tabindex="-1">NHook ve MinHook <a class="header-anchor" href="#nhook-ve-minhook" aria-label="Permalink to &quot;NHook ve MinHook&quot;">​</a></h1><p>Exoproc iki inline hook modeli sağlar. Seçim “hangisi daha iyi?” sorusu değil; hedef prologue&#39;u, detour gereksinimi ve kabul edilen çalışma zamanı davranışı sorusudur.</p><table tabindex="0"><thead><tr><th>Özellik</th><th>NHook</th><th>MinHook</th></tr></thead><tbody><tr><td>Patch</td><td>2 byte <code>EB FE</code></td><td>En az 5 byte göreli <code>jmp</code></td></tr><tr><td>Hit akışı</td><td>Thread park edilir, host <code>poll()</code> ile yakalar</td><td>Detour hedef process&#39;te doğrudan çalışır</td></tr><tr><td>Özgün prologue</td><td>Desteklenen talimatlar host tarafından simüle edilir</td><td>Taşınır ve trampoline içinde yürür</td></tr><tr><td>Detour</td><td>Yerleşik JS hit/resume modeli</td><td>Çağıranın sağladığı adres veya <code>CMachineCode</code></td></tr><tr><td>Başlıca sınır</td><td>Talimat simülasyonu ve hit lifecycle&#39;ı</td><td>Talimat relocation ve rel32 mesafesi</td></tr></tbody></table><h2 id="nhook-park-et-yakala-surdur" tabindex="-1">NHook: park et, yakala, sürdür <a class="header-anchor" href="#nhook-park-et-yakala-surdur" aria-label="Permalink to &quot;NHook: park et, yakala, sürdür&quot;">​</a></h2><p>NHook, hedef girişindeki tam talimatları en az iki byte kapsayana kadar çözer ve başlangıca <code>EB FE</code> yazar. Hedef thread bu sonsuz kısa atlamaya gelince host <code>poll()</code> ile hit&#39;i görür. <code>resume()</code> varsayılan akışta taşınan talimatların desteklenen alt kümesini simüle eder ve thread&#39;i fonksiyon gövdesinin devamına yönlendirir; istenirse dönüş değeri zorlanabilir.</p><p>Bu yaklaşım “trampoline yok” demektir, “her prologue desteklenir” demek değildir. Desteklenmeyen talimatlar, karmaşık control flow ve hit&#39;i zamanında işleyemeyen host tasarımı için uygunluğu test edin.</p><h2 id="minhook-detour-ve-trampoline" tabindex="-1">MinHook: detour ve trampoline <a class="header-anchor" href="#minhook-detour-ve-trampoline" aria-label="Permalink to &quot;MinHook: detour ve trampoline&quot;">​</a></h2><p>MinHook, hedefin yeterli başlangıç talimatını trampoline&#39;e taşır ve hedefe beş byte&#39;lık <code>jmp</code> yazar. <code>create()</code> trampoline&#39;i kurar ama patch yazmaz; <code>enable(detour)</code> detour&#39;u seçip patch&#39;i yükler. Detour uzak adres ise çağıranın bunu hedefte kullanılabilir hale getirmesi gerekir; <code>CMachineCode</code> verildiğinde accessor üzerinden taşınabilir.</p><p>Detour doğrudan rel32 erişiminde değilse MinHook, hedefe yakın ayrılmış bir relay kullanır. Relay/trampoline tahsisi, RIP-relative talimat relocation&#39;ı ve detour&#39;un kendi ABI&#39;si MinHook&#39;un en kritik doğrulama alanlarıdır. Detour&#39;un JavaScript ile iletişim protokolünü MinHook tanımlamaz.</p><p>Her iki hook için de <a href="/exoproc/previews/feature-docs/hooking/lifecycle">yaşam döngüsünü</a> ve kontrollü hedef üzerindeki enable/disable testini temel alın.</p>',10)])])}const u=a(i,[["render",d]]);export{c as __pageData,u as default};
